# Get hardware hash for consistent comparisons
.get_hardware_hash <- function() {
  info <- Sys.info()
  # Create a simple hash from system info
  hardware_string <- paste(
    info["sysname"],
    info["machine"],
    info["nodename"],
    sep = "_"
  )
  digest::digest(hardware_string, algo = "xxhash32")
}

# Save benchmark results to parquet database
.save_benchmark_results <- function(results_df, output_dir) {
  db_path <- fs::path(output_dir, "perf.parquet")

  # Check for arrow package
  if (!requireNamespace("arrow", quietly = TRUE)) {
    cli::cli_warn(
      c("Package {.pkg arrow} is required for parquet storage",
        "i" = "Install it with: install.packages('arrow')",
        "i" = "Results will not be saved to database")
    )
    return(invisible(NULL))
  }

  # If database exists, append; otherwise create new
  if (fs::file_exists(db_path)) {
    existing <- arrow::read_parquet(db_path)
    combined <- rbind(existing, results_df)
    arrow::write_parquet(combined, db_path)
  } else {
    arrow::write_parquet(results_df, db_path)
  }

  cli::cli_alert_success("Benchmark results saved to {db_path}")
}

# Print benchmark summary
.print_bench_summary <- function(results_df) {
  cli::cli_rule("Benchmark Summary")

  # Group by spec and language
  for (spec in unique(results_df$spec_id)) {
    cli::cli_h3(spec)
    spec_results <- results_df[results_df$spec_id == spec, ]

    for (i in seq_len(nrow(spec_results))) {
      row <- spec_results[i, ]
      cli::cli_alert_info(
        "{row$language}: {.val {format(row$median * 1e6, digits = 2)}\u00b5s} median ({row$n_itr} iterations)"
      )
    }
  }
}

