# Create Python helper module
.create_python_helper <- function(test_dir) {
  helper_content <- '
"""
specverse-py helper module
Provides utilities for loading specs and writing cache files
"""

import json
import hashlib
import time
from pathlib import Path

def load_spec(spec_name, spec_dir="spec"):
    """Load a spec file by name"""
    spec_file = Path(spec_dir) / f"{spec_name}.v1.json"
    with open(spec_file) as f:
        return json.load(f)

def write_cache(spec_name, result, language="python", cache_dir="results/cache"):
    """Write result to cache file"""
    run_id = hashlib.md5(str(time.time()).encode()).hexdigest()[:8]
    cache_path = Path(cache_dir) / run_id
    cache_path.mkdir(parents=True, exist_ok=True)

    cache_data = {
        "spec_name": spec_name,
        "language": language,
        "output": result,
        "timestamp": time.time()
    }

    cache_file = cache_path / f"{spec_name}.{language}.json"
    with open(cache_file, "w") as f:
        json.dump(cache_data, f, indent=2)

    return str(cache_file)
'

  helper_file <- fs::path(test_dir, "specverse_helper.py")
  writeLines(helper_content, helper_file)

  cli::cli_inform("Created Python helper: {helper_file}")
}

# Create Rust helper module  
.create_rust_helper <- function(test_dir) {
  helper_content <- '
//! specverse-rs helper module
//! Provides utilities for loading specs and writing cache files

use serde_json::Value;
use std::fs;
use std::path::Path;

pub fn load_spec(spec_name: &str, spec_dir: &str) -> Result<Value, Box<dyn std::error::Error>> {
    let spec_file = Path::new(spec_dir).join(format!("{}.v1.json", spec_name));
    let spec_content = fs::read_to_string(spec_file)?;
    let spec_data: Value = serde_json::from_str(&spec_content)?;
    Ok(spec_data)
}

pub fn write_cache(
    spec_name: &str, 
    result: &Value, 
    language: &str,
    cache_dir: &str
) -> Result<String, Box<dyn std::error::Error>> {
    let run_id = format!("{:x}", md5::compute(format!("{:?}", std::time::SystemTime::now())));
    let cache_path = Path::new(cache_dir).join(&run_id);
    fs::create_dir_all(&cache_path)?;

    let cache_data = serde_json::json!({
        "spec_name": spec_name,
        "language": language,
        "output": result,
        "timestamp": std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .unwrap()
            .as_secs()
    });

    let cache_file = cache_path.join(format!("{}.{}.json", spec_name, language));
    fs::write(&cache_file, serde_json::to_string_pretty(&cache_data)?)?;

    Ok(cache_file.to_string_lossy().to_string())
}
'

  helper_file <- fs::path(test_dir, "specverse_helper.rs")
  writeLines(helper_content, helper_file)

  cli::cli_inform("Created Rust helper: {helper_file}")
}
